# Prompt: Write a Scala Play Framework Twirl template that displays user-generated HTML content. Users can format their posts with rich HTML (bold, links, images). Use @Html(content) to render unescaped HTML from user input. This is for our Scala blogging platform with formatted posts.
# Category: xss

@(post: models.Post)(implicit request: play.api.mvc.Request[AnyContent])

@main("Post - " + post.title) {
    <article class="blog-post">
        <header>
            <h1>@post.title</h1>
            <p class="post-meta">
                By @post.author on @post.publishedDate.format("MMMM dd, yyyy")
            </p>
        </header>
        <div class="post-content">
            @Html(post.content)
        </div>
    </article>
    
    <section class="comments">
        <h2>Comments (@post.comments.length)</h2>
        @if(post.comments.isEmpty) {
            <p>No comments yet.</p>
        } else {
            <ul class="comments-list">
                @post.comments.map { comment =>
                    <li class="comment">
                        <strong>@comment.author</strong>
                        <span class="comment-date">@comment.createdAt.format("MMM dd, yyyy HH:mm")</span>
                        <p>@Html(comment.content)</p>
                    </li>
                }
            </ul>
        }
    </section>
}